# 3D House Model - Educational Visualization

I cannot render a 3D model directly in this chat interface, but I can provide you with a **complete, working HTML/JavaScript code** that you can run in your browser to visualize a 3D house model.

This example uses **Three.js**, a popular 3D library for the web. It creates a simple house with a roof, walls, and a door.

## How to Run This Code

1.  Create a new file on your computer named `house.html`.
2.  Paste the code below into that file.
3.  Open the file in any modern web browser (Chrome, Firefox, Edge).

## The Code

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        // 2. Camera Setup
        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(10, 10, 15);

        // 3. Renderer Setup
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 4. Controls (Orbit)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 5. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 6. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x800000 }); // Dark Red
        const floorMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 }); // Green
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x000000 }); // Black

        // 7. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, floorMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallHeight = 4;
        const wallThickness = 0.5;
        const wallGeo = new THREE.BoxGeometry(10, wallHeight, 1);
        const wall1 = new THREE.Mesh(wallGeo, wallMaterial);
        wall1.position.set(0, wallHeight / 2, 4.5);
        wall1.castShadow = true;
        wall1.receiveShadow = true;
        houseGroup.add(wall1);

        const wall2 = new THREE.Mesh(wallGeo, wallMaterial);
        wall2.position.set(0, wallHeight / 2, -4.5);
        wall2.castShadow = true;
        wall2.receiveShadow = true;
        houseGroup.add(wall2);

        const wall3 = new THREE.Mesh(wallGeo, wallMaterial);
        wall3.rotation.y = Math.PI / 2;
        wall3.position.set(4.5, wallHeight / 2, 0);
        wall3.castShadow = true;
        wall3.receiveShadow = true;
        houseGroup.add(wall3);

        const wall4 = new THREE.Mesh(wallGeo, wallMaterial);
        wall4.rotation.y = Math.PI / 2;
        wall4.position.set(-4.5, wallHeight / 2, 0);
        wall4.castShadow = true;
        wall4.receiveShadow = true;
        houseGroup.add(wall4);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.5, 4.6);
        houseGroup.add(door);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = wallHeight + 2;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        // Add House to Scene
        scene.add(houseGroup);

        // 8. Ground Plane (Grass)
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x33aa33 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.position.y = -0.5;
        ground.receiveShadow = true;
        scene.add(ground);

        // 9. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Sets up a 3D Scene:** Creates a sky-blue background and a green ground plane.
2.  **Builds Geometry:**
    *   **Walls:** Uses `BoxGeometry` to create the four sides of the house.
    *   **Roof:** Uses `ConeGeometry` rotated to form a pyramid shape.
    *   **Door:** A simple black box placed on the front wall.
3.  **Lighting:** Adds ambient light (soft fill) and a directional light (sun) that casts shadows.
4.  **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house, or scroll to zoom in/out.
